insert into public.question_options (id, question_id, option_text, position)
values
  ('40000000-0000-4000-8000-000000004e25', '30000000-0000-4000-8000-000000001389', 'Cost Plus Incentive Fee (CPIF) or Time and Materials (T&M) with a strict Ceiling Price.', 1),
  ('40000000-0000-4000-8000-000000004e26', '30000000-0000-4000-8000-000000001389', 'Firm Fixed Price (FFP) without any scope adjustment clause.', 2),
  ('40000000-0000-4000-8000-000000004e27', '30000000-0000-4000-8000-000000001389', 'Unfunded Purchase Order with vague payment terms.', 3),
  ('40000000-0000-4000-8000-000000004e28', '30000000-0000-4000-8000-000000001389', 'Fixed Price with Economic Price Adjustment linked solely to CPI index.', 4),
  ('40000000-0000-4000-8000-000000004e29', '30000000-0000-4000-8000-00000000138a', '1 year.', 1),
  ('40000000-0000-4000-8000-000000004e2a', '30000000-0000-4000-8000-00000000138a', '5 years.', 2),
  ('40000000-0000-4000-8000-000000004e2b', '30000000-0000-4000-8000-00000000138a', '10 years.', 3),
  ('40000000-0000-4000-8000-000000004e2c', '30000000-0000-4000-8000-00000000138a', '20 years.', 4),
  ('40000000-0000-4000-8000-000000004e2d', '30000000-0000-4000-8000-00000000138b', 'Award the contract immediately without reviewing technical capabilities.', 1),
  ('40000000-0000-4000-8000-000000004e2e', '30000000-0000-4000-8000-00000000138b', 'Disqualify all four vendors and cancel the infrastructure initiative.', 2),
  ('40000000-0000-4000-8000-000000004e2f', '30000000-0000-4000-8000-00000000138b', 'Conduct a formal price-reasonableness audit and request clarification to ensure the bidder understood scope requirements.', 3),
  ('40000000-0000-4000-8000-000000004e30', '30000000-0000-4000-8000-00000000138b', 'Force the second lowest bidder to match the abnormally low price.', 4),
  ('40000000-0000-4000-8000-000000004e31', '30000000-0000-4000-8000-00000000138c', 'Project engineers are legally forbidden from talking to vendors.', 1),
  ('40000000-0000-4000-8000-000000004e32', '30000000-0000-4000-8000-00000000138c', 'Scope changes are illegal under international trade law.', 2),
  ('40000000-0000-4000-8000-000000004e33', '30000000-0000-4000-8000-00000000138c', 'The vendor failed to submit a patent registration for the change.', 3),
  ('40000000-0000-4000-8000-000000004e34', '30000000-0000-4000-8000-00000000138c', 'Only authorized procurement personnel/contracting officers hold legal authority to commit contract variations.', 4),
